from abc import ABC, abstractmethod
from typing import Dict, Any
import json

class WeatherApiClient(ABC):
    @abstractmethod
    def fetch_weather_data(self, city: str) -> Dict[str, Any]:
        pass

class DataSaver(ABC):
    @abstractmethod
    def save_to_json(self, data: Dict[str, Any], filename: str) -> None:
        pass

class WeatherService:
    def __init__(self, api_client: WeatherApiClient, data_saver: DataSaver):
        self.api_client = api_client
        self.data_saver = data_saver

    def get_and_save_weather(self, city: str, filename: str) -> None:
        weather_data = self.api_client.fetch_weather_data(city)
        self.data_saver.save_to_json(weather_data, filename)

