from interfaces import WeatherApiClient, DataSaver, WeatherService
from typing import Dict, Any

class DIContainer:
    def __init__(self):
        self._services: Dict[str, object] = {}

    def register(self, name: str, service: object) -> None:
        self._services[name] = service

    def get(self, name: str) -> object:
        return self._services.get(name)

    def build_weather_service(self) -> WeatherService:
        api_client = self.get('weather_api_client')
        data_saver = self.get('data_saver')
