        return {'temperature': 20, 'humidity': 60}

class IWeatherRepository:
    @abc.abstractmethod
    def save_to_json_file(self, data: Dict):
        pass

class LocalJSONFileRepository(IWeatherRepository):
    def __init__(self, json_file_path: str):
        self.json_file_path = json_file_path

    def save_to_json_file(self, data: Dict):
        # Replace this with your actual JSON file writing code
        import json
        with open(self.json_file_path, 'w') as f:
            json.dump(data, f)

class IWeatherService:
