from abc import ABC, abstractmethod
import json
from typing import Any

class WeatherDataFetcher(ABC):
    @abstractmethod
    def fetch_weather_data(self) -> dict:
        pass

class WeatherDataSaver(ABC):
    @abstractmethod
    def save_to_json(self, data: dict) -> None:
        pass


class OpenWeatherMapAPI(WeatherDataFetcher):
    def __init__(self, api_key: str):
        self.api_key = api_key

    def fetch_weather_data(self) -> dict:
        # Simulate fetching weather data from an API
        response = {
            "name": "London",
            "weather": [{"description": "clear sky", "icon": "01d"}],
            "main": {"temp": 285.3, "humidity": 64}
        }
        return response


class JSONFileSaver(WeatherDataSaver):
    def __init__(self, file_path: str):
        self.file_path = file_path

    def save_to_json(self, data: dict) -> None:
        with open(self.file_path, 'w') as f:
            json.dump(data, f, indent=4)


class WeatherService:
    def __init__(
        self,
        weather_data_fetcher: WeatherDataFetcher,
        weather_data_saver: WeatherDataSaver
    ):
        self.weather_data_fetcher = weather_data_fetcher
        self.weather_data_saver = weather_data_saver

    def process_weather(self) -> None:
        weather_data = self.weather_data_fetcher.fetch_weather_data()
        self.weather_data_saver.save_to_json(weather_data)


class WeatherCLI:
    @staticmethod
    def main():
        api_key = "your_api_key_here"
        file_path = "weather_data.json"

        weather_fetcher = OpenWeatherMapAPI(api_key)
        weather_saver = JSONFileSaver(file_path)

        weather_service = WeatherService(weather_fetcher, weather_saver)
        weather_service.process_weather()

if __name__ == "__main__":
    WeatherCLI.main()
```

### Dependency Injection Setup

